using SkiaSharp.Views.Blazor;

namespace Repro;

public class CustomGLView : SKGLView, IDisposable
{
    private bool _disposed;

    // Must use 'new' because Dispose is not virtual.
    // Calls through IDisposable/SKGLView references will NOT call this method.
    public new void Dispose()
    {
        if (!_disposed)
        {
            _disposed = true;
            Console.WriteLine("Custom cleanup");
            base.Dispose();
        }
    }
}
